import {
    IMessageDataWrapper,
    IMessageParser,
} from '@nitrots/nitro-renderer/src/core';

export interface CorporationData {
    id: number;
    name: string;
    desc: string;
    icon: string;
    stock: number;
}

export class CorporationsListParser implements IMessageParser {
    private _data: CorporationData[] = [];

    public flush(): boolean {
        this._data = [];
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        const count = wrapper.readInt();

        for (let i = 0; i < count; i++) {
            const id = wrapper.readInt();
            const name = wrapper.readString();
            const desc = wrapper.readString();
            const icon = wrapper.readString();
            const stock = wrapper.readInt();

            this._data.push({ id, name, desc, icon, stock });
        }

        return true;
    }

    public get corporations(): CorporationData[] {
        return this._data;
    }
}